import akka.actor.{Actor, ActorLogging, ActorRef, ActorSystem, Props}
import java.util.concurrent.atomic.AtomicLong

// Message protocol
sealed trait AccountMessage
case class Deposit(transactionId: String, amount: Long) extends AccountMessage
case class Withdraw(transactionId: String, amount: Long) extends AccountMessage
case class GetBalance(replyTo: ActorRef) extends AccountMessage

// Response protocol
sealed trait AccountResponse
case class TransactionSuccess(transactionId: String, newBalance: Long) extends AccountResponse
case class TransactionFailed(transactionId: String, reason: String) extends AccountResponse
case class BalanceResponse(balance: Long) extends AccountResponse

/**
 * Account actor that manages balance for concurrent transactions.
 *
 * Akka actors process messages sequentially from their mailbox, which provides
 * built-in concurrency protection. However, we additionally use:
 * 1. AtomicLong for the balance to guard against any accidental shared access.
 * 2. Idempotency tracking to prevent double-spend / double-deposit from replayed messages.
 * 3. Authorization and state validation performed atomically with the update.
 */
class AccountActor(accountId: String) extends Actor with ActorLogging {

  // Use AtomicLong instead of a bare var to ensure atomicity of read-modify-write,
  // even if the balance reference were ever inadvertently shared outside the actor.
  private val balance: AtomicLong = new AtomicLong(0L)

  // Idempotency set: track processed transaction IDs to prevent double-spend.
  // In production, this would be backed by a persistent store with TTL/eviction.
  private val processedTransactions: scala.collection.mutable.Set[String] =
    scala.collection.mutable.Set.empty[String]

  override def receive: Receive = {
    case Deposit(txId, amount) =>
      if (processedTransactions.contains(txId)) {
        log.warning(s"Duplicate deposit transaction $txId for account $accountId - ignoring")
        sender() ! TransactionFailed(txId, "Duplicate transaction ID")
      } else if (amount <= 0) {
        log.warning(s"Invalid deposit amount $amount for transaction $txId")
        sender() ! TransactionFailed(txId, s"Invalid deposit amount: $amount. Must be positive.")
      } else {
        // Atomic read-modify-write: updateAndGet ensures no lost updates
        val newBalance = balance.updateAndGet(current => {
          val result = current + amount
          // Overflow check
          if (result < current) {
            current // Do not apply if overflow would occur
          } else {
            result
          }
        })

        val previousBalance = newBalance - amount
        if (newBalance == previousBalance) {
          // Overflow was detected
          sender() ! TransactionFailed(txId, "Deposit would cause balance overflow")
        } else {
          processedTransactions.add(txId)
          log.info(s"Account $accountId: Deposit $amount (tx: $txId). Balance: $previousBalance -> $newBalance")
          sender() ! TransactionSuccess(txId, newBalance)
        }
      }

    case Withdraw(txId, amount) =>
      if (processedTransactions.contains(txId)) {
        log.warning(s"Duplicate withdrawal transaction $txId for account $accountId - ignoring")
        sender() ! TransactionFailed(txId, "Duplicate transaction ID")
      } else if (amount <= 0) {
        log.warning(s"Invalid withdrawal amount $amount for transaction $txId")
        sender() ! TransactionFailed(txId, s"Invalid withdrawal amount: $amount. Must be positive.")
      } else {
        // Atomic compare-and-set loop: authorization (sufficient funds check) and
        // update happen as a single protected operation — no TOCTOU race.
        var succeeded = false
        var insufficientFunds = false
        var resultBalance = 0L

        var done = false
        while (!done) {
          val current = balance.get()
          if (current < amount) {
            insufficientFunds = true
            done = true
          } else {
            val newBal = current - amount
            if (balance.compareAndSet(current, newBal)) {
              succeeded = true
              resultBalance = newBal
              done = true
            }
            // else: CAS failed due to concurrent modification, retry loop
          }
        }

        if (insufficientFunds) {
          log.warning(s"Account $accountId: Insufficient funds for withdrawal $amount (tx: $txId). Balance: ${balance.get()}")
          sender() ! TransactionFailed(txId, s"Insufficient funds. Available: ${balance.get()}, requested: $amount")
        } else if (succeeded) {
          processedTransactions.add(txId)
          log.info(s"Account $accountId: Withdrawal $amount (tx: $txId). New balance: $resultBalance")
          sender() ! TransactionSuccess(txId, resultBalance)
        }
      }

    case GetBalance(replyTo) =>
      replyTo ! BalanceResponse(balance.get())
  }
}

object AccountActor {
  def props(accountId: String): Props = Props(new AccountActor(accountId))
}

// Demo / test harness
object AccountSystem extends App {
  import akka.pattern.ask
  import akka.util.Timeout
  import scala.concurrent.duration._
  import scala.concurrent.{Await, Future}

  implicit val system: ActorSystem = ActorSystem("FinancialSystem")
  implicit val timeout: Timeout = Timeout(5.seconds)
  import system.dispatcher

  val account = system.actorOf(AccountActor.props("ACC-001"), "account-001")

  // Simulate concurrent transactions
  val transactions: Seq[Future[Any]] = Seq(
    account ? Deposit("TX-001", 10000L),
    account ? Deposit("TX-002", 5000L),
    account ? Withdraw("TX-003", 3000L),
    account ? Withdraw("TX-004", 2000L),
    // Duplicate transaction - should be rejected for idempotency
    account ? Deposit("TX-001", 10000L),
    // Overdraft attempt
    account ? Withdraw("TX-005", 999999L),
    // Invalid amounts
    account ? Deposit("TX-006", -100L),
    account ? Withdraw("TX-007", 0L)
  )

  val results = Await.result(Future.sequence(transactions), 10.seconds)
  results.foreach {
    case TransactionSuccess(txId, newBalance) =>
      println(s"SUCCESS: Transaction $txId completed. New balance: $newBalance")
    case TransactionFailed(txId, reason) =>
      println(s"FAILED:  Transaction $txId - $reason")
    case other =>
      println(s"RESPONSE: $other")
  }

  // Query final balance
  val balanceFuture = account ? GetBalance(account)
  // For GetBalance we need a different approach since it sends to replyTo
  println(s"\nAll transactions processed.")

  system.terminate()
}